import { ethers } from "ethers";

// Function to connect to the Ethereum network
async function connectToNetwork() {
  if (window.ethereum) {
    try {
      await window.ethereum.request({ method: 'eth_requestAccounts' });
      const provider = new ethers.providers.Web3Provider(window.ethereum);
      const signer = provider.getSigner();
      return { provider, signer };
    } catch (error) {
      console.error("User denied account access");
    }
  } else {
    console.error("Ethereum provider not found");
  }
}

// Function to send a transaction
async function sendTransaction(contract, methodName, methodArgs, value = null) {
  const { provider, signer } = await connectToNetwork();
  
  if (provider && signer) {
    const contractInstance = new ethers.Contract(contract.address, contract.abi, signer);
    try {
      let tx;
      if (value) {
        tx = await contractInstance[methodName](...methodArgs, { value });
      } else {
        tx = await contractInstance[methodName](...methodArgs);
      }
      const receipt = await tx.wait();
      console.log("Transaction successful:", receipt);
    } catch (error) {
      console.error("Transaction failed:", error);
    }
  }
}

// Example usage:
const contractABI = [
  "function exampleFunction(uint256 amount, address recipient)"
];
const contractAddress = "0xYourContractAddressHere";

sendTransaction(
  { address: contractAddress, abi: contractABI },
  "exampleFunction",
  [100, "0xRecipientAddress"]
);